import { describe, test, expect } from 'bun:test';
import { QuantumWasmBridge } from '../betty/quantum/bridge.js';

describe('QuantumWasmBridge', () => {
    test('processes FORK edge', () => {
        const bridge = new QuantumWasmBridge();
        const result = bridge.processAstEdge('FORK', 1, 2);
        expect(result).toContain('WASM');
        expect(result).toContain('FORK');
    });

    test('processes RACE edge', () => {
        const bridge = new QuantumWasmBridge();
        const result = bridge.processAstEdge('RACE', 2, 1);
        expect(result).toContain('WASM');
        expect(result).toContain('RACE');
    });

    test('processes FOLD edge', () => {
        const bridge = new QuantumWasmBridge();
        const result = bridge.processAstEdge('FOLD', 2, 1);
        expect(result).toContain('WASM');
        expect(result).toContain('FOLD');
    });

    test('processes COLLAPSE as FOLD', () => {
        const bridge = new QuantumWasmBridge();
        const result = bridge.processAstEdge('COLLAPSE', 2, 1);
        expect(result).toContain('WASM');
        expect(result).toContain('COLLAPSE');
    });

    test('processes VENT edge', () => {
        const bridge = new QuantumWasmBridge();
        const result = bridge.processAstEdge('VENT', 1, 1);
        expect(result).toContain('WASM');
        expect(result).toContain('VENT');
    });

    test('processes INTERFERE edge', () => {
        const bridge = new QuantumWasmBridge();
        const result = bridge.processAstEdge('INTERFERE', 2, 1);
        expect(result).toContain('WASM');
        expect(result).toContain('INTERFERE');
    });

    test('ignores unknown edge type', () => {
        const bridge = new QuantumWasmBridge();
        const result = bridge.processAstEdge('UNKNOWN', 1, 1);
        expect(result).toContain('Ignored');
    });

    test('tracks metrics across multiple edges', () => {
        const bridge = new QuantumWasmBridge();
        bridge.processAstEdge('FORK', 1, 3);
        bridge.processAstEdge('FOLD', 3, 1);
        const metrics = bridge.getMetrics();
        expect(metrics).toContain('Paths');
        expect(metrics).toContain('Beta1');
    });

    test('FORK then FOLD returns beta1 toward zero', () => {
        const bridge = new QuantumWasmBridge();
        bridge.processAstEdge('FORK', 1, 2);
        const afterFork = bridge.getMetrics();
        expect(afterFork).toContain('Beta1: 1');

        bridge.processAstEdge('FOLD', 2, 1);
        const afterFold = bridge.getMetrics();
        expect(afterFold).toContain('Beta1: 0');
    });
});
